import{_ as s,o as a,c as n,a as p}from"./chunks/framework.8tiMeCK-.js";const h=JSON.parse('{"title":"11.6  [K]GDB 进阶技巧与杂项","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_debugging/ch11_6.md","filePath":"notes/linux_kernel_debugging/ch11_6.md","lastUpdated":null}'),i={name:"notes/linux_kernel_debugging/ch11_6.md"};function t(d,e,l,o,r,c){return a(),n("div",null,[...e[0]||(e[0]=[p(`<h1 id="_11-6-k-gdb-进阶技巧与杂项" tabindex="-1">11.6 [K]GDB 进阶技巧与杂项 <a class="header-anchor" href="#_11-6-k-gdb-进阶技巧与杂项" aria-label="Permalink to &quot;11.6  [K]GDB 进阶技巧与杂项&quot;">​</a></h1><p>上节我们用 <code>hbreak</code> 咬住了 <code>do_init_module</code>，算是彻底解决了「模块加载瞬间消失」的问题。但你一旦真的用 KGDB 跑起来，就会发现它像个深不见底的工具箱——大部分时候你只用螺丝刀，但当你真正需要那个弯头钳子时，最好知道它躺在哪个角落。</p><p>GDB 是个庞大的程序，功能多到令人发指。这一节我们不讲基础流程，专门来盘点那些容易被人忽略、但在关键时刻能救命的高级技巧。有些是内核自带的增强脚本，有些是 GDB 原生被低估的特性。</p><hr><h3 id="启用内核-gdb-脚本-config-gdb-scripts" tabindex="-1">启用内核 GDB 脚本 (CONFIG_GDB_SCRIPTS) <a class="header-anchor" href="#启用内核-gdb-脚本-config-gdb-scripts" aria-label="Permalink to &quot;启用内核 GDB 脚本 (CONFIG_GDB_SCRIPTS)&quot;">​</a></h3><p>这件事很多人不知道：Linux 内核源码树里其实藏着一堆写好的 Python 脚本，它们能直接在 GDB 里当作命令用。</p><p>从 4.0 内核开始，开发者就在 <code>scripts/gdb</code> 目录下塞了这些东西。它们不是普通的脚本，而是挂载在 GDB 内部的钩子。要启用它们，第一步是在内核配置里打开开关：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CONFIG_GDB_SCRIPTS=y</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>打开这个选项后，内核编译会生成 <code>vmlinux-gdb.py</code>。但 GDB 默认为了安全，不会随便加载自动运行的脚本——怕你哪天不小心下了个恶意内核源码把自家电脑黑了。</p><p>所以第二步，你需要告诉 GDB：「嘿，这个目录的脚本是我自家的，放心加载」。</p><p>在你的 <code>~/.gdbinit</code> 文件里加上这一行：</p><div class="language-gdb vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">gdb</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>add-auto-load-safe-path /path/to/linux/kernel/scripts/gdb/vmlinux-gdb.py</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果你懒得写绝对路径（或者你经常换内核源码目录），可以用简单粗暴但更通用的写法：</p><div class="language-gdb vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">gdb</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>add-auto-load-safe-path /</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这就相当于解除了所有安全限制。只要做完这一步，GDB 再次加载 <code>vmlinux</code> 时，就会自动解析这些 Python 脚本。</p><p>你凭什么知道它生效了？</p><p>在 GDB 里输入：</p><div class="language-gdb vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">gdb</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) apropos lx-</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果屏幕刷出一堆带 <code>lx-</code> 前缀的命令，那就说明 OK 了。</p><p><code>lx-</code> 前缀代表 Linux，<code>_</code> 前缀（<code>lx_</code>）代表辅助函数。</p><p>图 11.18 显示了这些命令的概貌。你会发现有些名字很眼熟：<code>lx-dmesg</code>（看内核日志）、<code>lx-cmdline</code>（看启动参数）、<code>lx-lsmod</code>（看加载的模块）、<code>lx-iomem</code>（看内存布局）……</p><p>这有什么用？太有用了。</p><p>以前你要查内核日志，得在目标系统里敲 <code>dmesg</code>，或者还得把日志重定向到文件。现在你在 GDB 调试态下，不用退出，直接 <code>lx-dmesg</code>，日志就在你眼前流出来。这对调试「死机前最后一刻发生了什么」极其有效。</p><p>想要某个命令的帮助？GDB 的 help 依然通用：</p><div class="language-gdb vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">gdb</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) help lx-lsmod</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这玩意儿需要 GDB 7.2 或更高版本。官方文档在 <a href="https://docs.kernel.org/dev-tools/gdb-kernel-debugging.html" target="_blank" rel="noreferrer">这里</a>，建议你看完直接上手试。</p><hr><h3 id="真实硬件上的-target-remote-1234-为什么不工作" tabindex="-1">真实硬件上的 target remote :1234 为什么不工作？ <a class="header-anchor" href="#真实硬件上的-target-remote-1234-为什么不工作" aria-label="Permalink to &quot;真实硬件上的 target remote :1234 为什么不工作？&quot;">​</a></h3><p>我们在 QEMU 上跑得很顺，<code>target remote :1234</code> 一连就通。但你一旦换成两台真实机器，一根串口线连着，同样的命令可能会死给你看。</p><p>这就是物理世界的恶意——连接层问题。</p><p>如果你的 GDB 客户端报错说连不上，或者提示奇怪的警告（比如 <code>warning: unrecognized item &quot;timeout&quot; in &quot;qSupported&quot; response</code>），别怀疑内核配置，先怀疑线。</p><p>在折腾 KGDB 之前，先干一件事：确认双向通信是通的。</p><p>假设你的串口线接在 Host 的 <code>/dev/ttyUSB0</code>，Target 接在 <code>/dev/ttyS0</code>。</p><p>在 Host 上（需要 root 权限）：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;hello, target&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/ttyUSB0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>在 Target 上：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/ttyS0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果你在 Target 的屏幕上看到了 <code>hello, target</code>，说明 Host -&gt; Target 没问题。</p><p>反过来，在 Target 上：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;hello, host&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/ttyS0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>在 Host 上：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /dev/ttyUSB0</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>如果这一步也通了，说明物理链路是好的。</p><p>如果链路是好的但 KGDB 还是不工作，可能是因为 USB 转串口的适配器问题。</p><p>这里有个经验之谈：Host 端用 USB 转串口通常没问题，但 Target 端如果是通过 USB 转串口接到 KGDB，有些内核驱动配合得不好。Target 最好直接接在主板的原生串口（COM 口）上，或者走网络（Ethernet/Wireless）。</p><hr><h3 id="设置-sysroot-——-找不到库怎么办" tabindex="-1">设置 sysroot —— 找不到库怎么办？ <a class="header-anchor" href="#设置-sysroot-——-找不到库怎么办" aria-label="Permalink to &quot;设置 sysroot —— 找不到库怎么办？&quot;">​</a></h3><p>当你拿着 x86 电脑去调试 ARM 板子（或者远程交叉调试）时，GDB 会遇到一个尴尬的问题：它知道怎么读 ELF 文件，但它不知道板子上的 <code>/lib</code> 库文件在哪里。</p><p>如果你尝试 step 进入一个库函数，GDB 可能会报错说找不到 <code>.so</code> 文件。</p><p>解决办法有两个：</p><ol><li><p><strong>用交叉工具链里的 GDB</strong> 别用系统自带的 <code>gdb</code>，去用你的工具链专用的那个，比如 <code>arm-none-linux-gnueabihf-gdb</code>。</p></li><li><p><strong>告诉 GDB 目标根文件系统在哪</strong> 在 GDB 里设置 <code>sysroot</code> 变量：</p><div class="language-gdb vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">gdb</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) set sysroot /path/to/target/rootfs</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>或者设置 <code>solib-search-path</code>：</p><div class="language-gdb vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">gdb</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) set solib-search-path /path/to/target/rootfs/lib</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这样 GDB 就知道去哪里找那些依赖库了。这在调试用户态程序（通过内核挂载的 rootfs）时尤为重要。</p></li></ol><hr><h3 id="gdb-的-tui-模式-——-告别纯黑底白字" tabindex="-1">GDB 的 TUI 模式 —— 告别纯黑底白字 <a class="header-anchor" href="#gdb-的-tui-模式-——-告别纯黑底白字" aria-label="Permalink to &quot;GDB 的 TUI 模式 —— 告别纯黑底白字&quot;">​</a></h3><p>很多人嫌弃 GDB，是因为觉得它复古：一行命令，一行输出，来回翻页累死人。</p><p>其实 GDB 有个自带图形界面的模式，叫 TUI（Text User Interface）。不用装插件，不用 IDE，加个参数就行：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gdb</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -tui</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -q</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vmlinux</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>回车的一瞬间，你的终端变了。</p><p>窗口会被切成两半：上面是源代码，下面是 GDB 命令行。你可以一边看代码，一边敲命令，不用再频繁输 <code>list</code> 或 <code>l</code>。</p><p>想看三栏？按 <code>Ctrl-x</code> 然后按 <code>2</code>（先按 Ctrl+X，松开，再按 2）。</p><p>这就把 CPU 寄存器视图也调出来了。图 11.19 展示了这个效果：寄存器、源码、命令，三位一体。</p><p>而且这玩意儿是动态的——如果某个寄存器在上一条指令执行后变了，它会高亮显示。这在单步调试汇编时极其好用。</p><p>如果你想切换视图（比如从源码切到汇编），可以用 <code>Ctrl-x</code> 然后按 <code>1</code>（自动）或者 <code>Ctrl-x</code> 再按 <code>a</code>（汇编模式）。</p><p><strong>表 11.1 给出了常用的快捷键，值得打印出来贴在显示器边框上。</strong></p><p>比如：</p><ul><li><code>Ctrl-x 1</code>: 单列模式（只看源码或汇编）</li><li><code>Ctrl-x 2</code>: 双列模式</li><li><code>Ctrl-x a</code>: 切换汇编/源码混合模式</li><li><code>Ctrl-p / Ctrl-n</code>: 上/下一条命令（历史记录）</li></ul><p>这个模式一旦用顺手，你会发现它其实跟那些带 GUI 的 IDE（比如 VS Code, Eclipse）没什么两样，甚至还更轻量。</p><p>顺便说一句，<strong>单步执行汇编指令</strong>用 <code>si</code> (stepi) 或者 <code>ni</code> (nexti)。想看汇编代码用 <code>disas</code> 或 <code>/m</code> 修饰符（<code>disas /m func_name</code>），这些在 TUI 模式下配合起来简直是神器。</p><hr><h3 id="遇到-value-optimized-out-怎么办" tabindex="-1">遇到 <code>&lt;value optimized out&gt;</code> 怎么办？ <a class="header-anchor" href="#遇到-value-optimized-out-怎么办" aria-label="Permalink to &quot;遇到 \`&lt;value optimized out&gt;\` 怎么办？&quot;">​</a></h3><p>这是所有内核新人最恐慌的时刻之一。</p><p>你在 GDB 里想看一个局部变量 <code>i</code>：</p><div class="language-gdb vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">gdb</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) p i</span></span>
<span class="line"><span>$1 = &lt;value optimized out&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>什么鬼？GDB 怼你一脸：这变量被优化掉了。</p><p>这是编译器的锅。GCC 打开 <code>-O2</code> 或 <code>-O3</code> 后，它发现你那个 <code>i</code> 其实可以全程放在寄存器里，根本不用去内存里存取。于是，内存里没有它的影子，GDB 去内存里找（这是它默认的行为），自然找不到。</p><p><strong>遇到这种情况，别慌。你有三条路：</strong></p><ol><li><p><strong>去看寄存器</strong> 这就需要懂 CPU 的 ABI（Application Binary Interface）。我们在第 4 章讲 Kprobes 时提到过这个。根据函数调用约定，参数通常是放在前几个寄存器（比如 x86 的 <code>rdi</code>, <code>rsi</code>, <code>rdx</code>...）里的。如果变量没被 spill 到栈上，那它一定在某个寄存器里躺着。 你可以直接 <code>info registers</code> 看看，或者在 TUI 模式下盯着上面的寄存器窗看。</p></li><li><p><strong>打开 DWARF 4 调试信息</strong> 在内核配置里开启 <code>CONFIG_DEBUG_INFO_DWARF4</code>。这个选项会让调试信息更详细，虽然在优化代码下也不能保证 100% 能解析出变量，但成功率会显著提高。</p></li><li><p><strong>换 TUI 模式看汇编</strong> 如果你看不到变量名，就看它在干什么。源代码看不懂，就去看对应的汇编指令（<code>disas /m</code>）。汇编是不会撒谎的，你总能找到那个寄存器在哪里被操作。</p></li></ol><hr><h3 id="gdb-的便利函数与自定义宏" tabindex="-1">GDB 的便利函数与自定义宏 <a class="header-anchor" href="#gdb-的便利函数与自定义宏" aria-label="Permalink to &quot;GDB 的便利函数与自定义宏&quot;">​</a></h3><p>如果你发现自己天天在敲同样的命令序列，你该写宏了。</p><p>GDB 的宏语法非常简单，就是 <code>define ... end</code>。你可以把这些宏写在 <code>~/.gdbinit</code> 里，启动 GDB 时它们会自动加载。</p><p>举个例子，每次调试 QEMU 都要连端口、设断点，很烦。写个宏：</p><div class="language-gdb vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">gdb</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># ~/.gdbinit</span></span>
<span class="line"><span>define connect_qemu</span></span>
<span class="line"><span>  target remote :1234</span></span>
<span class="line"><span>  hbreak start_kernel</span></span>
<span class="line"><span>  hb panic</span></span>
<span class="line"><span>  hb do_init_module</span></span>
<span class="line"><span>  b do_fsync</span></span>
<span class="line"><span>end</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>以后进 GDB 只需要敲 <code>connect_qemu</code>，一切全搞定。</p><p>再来个实用点的：看栈。</p><div class="language-gdb vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">gdb</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>define xs</span></span>
<span class="line"><span>  printf &quot;Examine stack:\\n&quot;</span></span>
<span class="line"><span>  x/8x $sp</span></span>
<span class="line"><span>  printf &quot;---\\n&quot;</span></span>
<span class="line"><span>  x/8x $sp-32</span></span>
<span class="line"><span>end</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>这个宏 <code>xs</code> 会打印出栈指针 <code>$sp</code> 前后的一坨内存，对查栈溢出或者找局部变量很有用。</p><p>GDB 还有一些内置的便利函数（Convenience Functions），很多需要 Python 支持：</p><ul><li><code>$_memeq(buf1, buf2, length)</code>: 比较两块内存是否一样。</li><li><code>$_regex(str, regex)</code>: 正则匹配。</li><li><code>$_strlen(str)</code>: 算字符串长度。</li></ul><p>这些都能在 <code>help</code> 文档里找到。更多宏的例子可以去内核文档里抄：<a href="https://www.kernel.org/doc/Documentation/admin-guide/kdump/gdbmacros.txt" target="_blank" rel="noreferrer">Documentation/admin-guide/kdump/gdbmacros.txt</a>。</p><hr><h3 id="高级断点-条件断点与观察点" tabindex="-1">高级断点：条件断点与观察点 <a class="header-anchor" href="#高级断点-条件断点与观察点" aria-label="Permalink to &quot;高级断点：条件断点与观察点&quot;">​</a></h3><p>普通的 <code>break</code> 太机械了。有时候你需要更细腻的控制。</p><h4 id="条件断点" tabindex="-1">条件断点 <a class="header-anchor" href="#条件断点" aria-label="Permalink to &quot;条件断点&quot;">​</a></h4><p>想象你在调试一个循环，这个循环跑 10 万次。你怀疑 bug 出在最后一次循环。</p><p>难道你要按 10 万次 <code>c</code> (continue)？</p><p>不。用条件断点：</p><div class="language-gdb vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">gdb</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) break loop_function if i == 99999</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>或者如果断点已经设好了：</p><div class="language-gdb vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">gdb</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) condition 1 i == 99999</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这样，只有当 <code>i</code> 等于 99999 时，GDB 才会停下来。这在 Off-by-one 错误排查中简直是救命稻草。</p><h4 id="临时断点" tabindex="-1">临时断点 <a class="header-anchor" href="#临时断点" aria-label="Permalink to &quot;临时断点&quot;">​</a></h4><p>有时候你只想「暂停一次」，不想后续总被这个断点烦。用 <code>tbreak</code>：</p><div class="language-gdb vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">gdb</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) tbreak some_function</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>它命中一次后就会自动删除，省得你手动 <code>disable</code> 或 <code>delete</code>。</p><h4 id="硬件观察点" tabindex="-1">硬件观察点 <a class="header-anchor" href="#硬件观察点" aria-label="Permalink to &quot;硬件观察点&quot;">​</a></h4><p>这是 GDB 最强力的功能之一，甚至比断点还强。</p><p>普通断点是「停在这行代码」。观察点是「停在这个变量被修改/读取的时候」。</p><p>它用的是 CPU 的硬件调试寄存器（DR0-DR3 on x86），速度极快，不像软件断点那样还要替换指令。</p><p>怎么用？</p><ul><li><code>watch &lt;var&gt;</code>: 变量<strong>被写入</strong>时停下。</li><li><code>rwatch &lt;var&gt;</code>: 变量<strong>被读取</strong>时停下。</li><li><code>awatch &lt;var&gt;</code>: 读写都停。</li></ul><p>举个例子，<code>jiffies_64</code> 是内核的全局时钟变量，每次时钟中断都会加 1。</p><p>如果我们对它下观察点：</p><div class="language-gdb vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">gdb</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) watch jiffies_64</span></span>
<span class="line"><span>Hardware watchpoint 1: jiffies_64</span></span>
<span class="line"><span>(gdb) c</span></span>
<span class="line"><span>Continuing.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Hardware watchpoint 1: jiffies_64</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Old value = 4294888091</span></span>
<span class="line"><span>New value = 4294888092</span></span>
<span class="line"><span>0x (... some address in timer interrupt handler ...)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>看图 11.20。GDB 会在变量变化的瞬间暂停，告诉你旧值是多少、新值是多少，还会顺便停在修改它的那一行代码上。</p><p>这时候你用 <code>bt</code> (backtrace)，就能一眼看到是谁改了这个变量。</p><p>这对于调试「谁把我的指针改成了 NULL」或者「谁在乱改我结构体的成员」这类幽灵 Bug，是核武器级别的手段。</p><p><strong>注意</strong>：硬件断点/观察点是有限的资源（x86 通常只有 4 个），用完就没了。如果 GDB 提示 <code>can&#39;t set breakpoints</code>，可能就是硬件资源耗尽了。</p><hr><h3 id="杂项技巧" tabindex="-1">杂项技巧 <a class="header-anchor" href="#杂项技巧" aria-label="Permalink to &quot;杂项技巧&quot;">​</a></h3><p>最后再丢几个零碎但好用的小技巧：</p><ol><li><p><strong>Tab 补全</strong> 在 GDB 里敲命令、变量名、函数名，按 Tab 可以补全。如果匹配项太多，按两下 Tab 会列出所有可能。</p></li><li><p><strong>根据 Oops 的地址定位代码</strong> 还记得第 7 章 Oops 吗？如果 Oops 给了你一个函数名 + 偏移量（比如 <code>my_func+0x5c</code>），你在 GDB 里可以用：</p><div class="language-gdb vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">gdb</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) list *my_func+0x5c</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>直接跳到那一行代码。</p></li><li><p><strong>在 GDB 里跑 Shell</strong> 不用退出 GDB，直接：</p><div class="language-gdb vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">gdb</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>(gdb) shell ls -l</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这在调试需要临时查个文件或者改个东西时很方便。</p></li><li><p><strong>反向调试</strong> GDB 甚至支持「倒带」（record / reverse），不过这个功能非常耗内存，在 KGDB 这种远程调试场景下可能不太现实。如果你在本地调试用户态程序，可以试试 <code>record btrace</code>。</p></li></ol><hr><p>写到这里，GDB（以及 KGDB）的工具箱算是翻到底了。</p><p>现在的你，不仅知道怎么连上内核、怎么设断点，还知道怎么用 Python 脚本查日志，怎么用 TUI 模式像 IDE 一样工作，怎么用硬件观察点抓那个乱改变量的「鬼」。</p><p>接下来的最后一章，我们将把目光从「怎么调试」收回到「整个系统的设计」——看看还有哪些系统级的调试手段能帮我们把最后的谜题解开。</p><p>我会在那里等你。</p>`,126)])])}const u=s(i,[["render",t]]);export{h as __pageData,u as default};
